export const frenchGuideProfiles: FrenchGuideProfile[] = [
  { id: "factory-guide", enPath: "/resources/evaluate-oem-gym-equipment-factory-china", frPath: "/fr/blog/evaluer-usine-equipements-fitness-chine", title: "Évaluer une usine d’équipements fitness en Chine | Guide B2B", description: "Méthode pour vérifier une usine : produit, processus, capacité, échantillon, contrôle qualité, OEM, emballage et preuves avant commande.", h1: "Comment évaluer une usine d’équipements fitness en Chine", keyword: "évaluer fabricant équipements fitness Chine", intent: "Qualification fournisseur avant commande",
    direct: "Évaluez d’abord la capacité à reproduire votre produit et à prouver les contrôles, pas la qualité d’une présentation commerciale. Vérifiez identité, site, procédés, échantillon, critères mesurables, capacité liée au produit, conditionnement et gestion des écarts.", definition: "Une évaluation d’usine combine vérification documentaire, entretien technique, vidéo ou visite, essai d’échantillon et éventuellement audit indépendant. Elle porte sur l’entreprise réelle et sur la famille commandée.", decision: "Choisissez un modèle représentatif et demandez au fournisseur d’expliquer matière, étapes, points critiques et moyens de mesure. Comparez ses réponses avec le devis et l’échantillon. Les incohérences valent davantage qu’une liste de slogans.", process: "Procédez par étapes : identité et adresse, correspondance produit-processus, documents, observation de production, commande d’échantillon, validation, lot pilote ou série, puis inspection avant expédition. Affectez chaque question ouverte à une personne et une date.", quality: "Demandez comment sont gérés réception matière, contrôles en cours, mesure finale, étalonnage et non-conformités. Pour les poids libres, contrôlez masse, dimensions, liaison, surface, marquage et emballage ; pour les racks, ajoutez géométrie, soudure, finition, fonction et quincaillerie.", practical: "Posez la même question technique à plusieurs fournisseurs et notez précision, preuve et délai de réponse. Une vidéo utile montre la date, le code du produit et l’étape. Pour un enjeu important, mandatez un auditeur ou inspecteur indépendant.", risks: "Adresse floue, coordonnées bancaires changeantes, uniquement des photos de catalogue, délais impossibles, certificats non reliés au produit, refus d’échantillon ou de contrôle sont des signaux à clarifier avant paiement.", comparison: [["Commercial", "Catalogue large et coordination", "Identifier le site réel"], ["Usine spécialisée", "Maîtrise d’une famille", "Vérifier largeur et capacité"], ["Audit", "Photo structurée à un instant", "Vérifier date et périmètre"], ["Échantillon", "Preuve du modèle", "Confirmer répétabilité en série"]], checklist: ["Vérifier identité, adresse et compte bancaire", "Relier le produit aux procédés réels", "Observer machines, outils et opérateurs", "Examiner plan QC et mesures", "Commander un échantillon identifié", "Valider capacité et calendrier", "Préparer inspection et traitement des écarts", "Contrôler emballage et documents export"], faq: [["Une visioconférence suffit-elle ?", "Elle peut filtrer un fournisseur, mais ne remplace pas toujours audit, échantillon et inspection."], ["Faut-il visiter chaque usine ?", "Le niveau de contrôle dépend du risque, du montant, de la nouveauté et de la complexité."], ["Comment vérifier la capacité ?", "Reliez-la au produit, aux outils, aux équipes, à la matière et au calendrier du projet."], ["Un certificat prouve-t-il la qualité ?", "Non. Vérifiez émetteur, titulaire, site, produit, portée et validité."]], links: [["factory", "Voir l’usine PowerBaseFit"], ["commercial-free-weight-rfq", "Préparer une RFQ"], ["oem-sample-approval-free-weights", "Valider un échantillon"], ["contact", "Contacter PowerBaseFit"]] },
  { id: "dumbbells-guide", enPath: "/resources/how-to-choose-commercial-dumbbells", frPath: "/fr/blog/choisir-halteres-professionnels-salle-sport", title: "Choisir des haltères professionnels pour une salle | Guide B2B", description: "Comparez haltères hexagonaux, ronds, caoutchouc, PU, TPU, CPU, poids, poignées, racks, entretien, QC et budget d’achat.", h1: "Comment choisir des haltères professionnels pour une salle de sport", keyword: "choisir haltères professionnels salle de sport", intent: "Choix produit et planification de gamme",
    direct: "Choisissez les haltères selon utilisateurs, paliers de poids, forme, revêtement, poignée, rack, nettoyage, remplacement et budget total. Commencez par le programme d’entraînement et la fréquentation avant de comparer caoutchouc, PU, TPU ou CPU.", definition: "Un assortiment professionnel est un ensemble cohérent de paires et de paliers, conçu pour la zone, les utilisateurs et le rangement. La mention professionnelle ne remplace pas les critères de masse, liaison, finition et maintenance.", decision: "Une tête hexagonale limite le roulement et facilite certains exercices au sol ; une tête ronde favorise une présentation uniforme sur rack. Les matériaux influencent toucher et finition mais doivent être évalués avec formulation, échantillon et usage.", process: "Dessinez la zone, estimez utilisateurs simultanés, listez paliers et paires, choisissez le rack, puis comparez les constructions. Validez un poids léger, moyen et lourd avant la série afin d’observer proportion, poignée et liaison.", quality: "Contrôlez masse réelle, dimensions, concentricité, poignée, texture, liaison, marquage et surface. La vérification d’une gamme ne doit pas se limiter à une seule paire : les extrêmes exposent d’autres risques de procédé.", practical: "Pour une salle généraliste, la continuité des paliers et la disponibilité des poids sollicités comptent davantage qu’une variante décorative. Pour un distributeur, ajoutez nombre de SKU, carton par paire, code-barres et politique de réassort.", risks: "Sous-estimer la longueur de rack, multiplier les poids peu vendus, comparer uniquement le prix au kilo, ignorer odeur ou nettoyage et ne pas conserver de référence approuvée augmentent le coût réel.", comparison: [["Hexagonal", "Stabilité et exercices au sol", "Vérifier dimensions sur rack"], ["Rond", "Présentation régulière", "Limiter roulement hors rack"], ["Caoutchouc", "Choix commercial répandu", "Formulation et odeur variables"], ["PU/TPU/CPU", "Finitions et constructions diverses", "Comparer l’échantillon réel"]], checklist: ["Profil des utilisateurs", "Poids minimum et maximum", "Paliers et paires par poids", "Forme des têtes", "Matière et finition", "Dimensions de poignée", "Rack et circulation", "Tolérance de masse", "Logo et marquage", "Réassort et pièces de rack"], faq: [["Hexagonal ou rond ?", "Le meilleur choix dépend du rangement, des exercices, de la circulation et de la présentation."], ["Quel revêtement choisir ?", "Comparez échantillons, entretien, aspect, odeur et coût total plutôt que le seul nom matière."], ["Combien de paires par poids ?", "Basez-vous sur fréquentation et historique d’utilisation ; les poids demandés peuvent nécessiter plusieurs paires."], ["Faut-il tester plusieurs poids ?", "Oui, au moins des variantes légère, moyenne et lourde."]], links: [["dumbbells-category", "Voir les haltères"], ["dumbbell-weighing-guide", "Contrôler la masse"], ["commercial-dumbbell-set-planning", "Planifier un set"], ["contact", "Demander une proposition"]] },
  { id: "plates-guide", enPath: "/resources/weight-plates-vs-bumper-plates-b2b-guide", frPath: "/fr/blog/disques-musculation-vs-bumper-plates", title: "Disques de musculation ou bumper plates : comparaison B2B", description: "Comparez disques classiques et bumper plates selon usage, diamètre, épaisseur, bruit, chute, stockage, coût et contrôle qualité.", h1: "Disques de musculation ou bumper plates : que choisir ?", keyword: "disques de musculation ou bumper plates", intent: "Comparaison avant achat",
    direct: "Choisissez des bumper plates lorsque l’usage prévoit des dépôts ou chutes contrôlées sur une plateforme adaptée ; choisissez des disques compacts lorsque la charge, le stockage et la musculation classique dominent. L’usage autorisé reste le premier critère.", definition: "Un disque classique charge une barre sans présumer qu’il peut être lâché. Un bumper plate utilise une construction élastomère et un diamètre commun pour les mouvements d’haltérophilie, sous réserve du sol et des règles d’utilisation.", decision: "Comparez alésage, diamètre, épaisseur, masse, tolérance, insert, rebond, bruit et odeur. L’épaisseur influence la charge maximale sur la barre ; le diamètre et la matière influencent le comportement au sol.", process: "Listez exercices, charges, barres, plateformes et rangement. Décidez quelles zones peuvent recevoir des chutes, puis demandez des données et un échantillon. Testez dans des conditions représentatives sans dépasser l’usage autorisé.", quality: "Pour les deux familles, vérifiez masse, alésage, planéité, insert, marquage et surface. Pour les bumper plates, examinez liaison insert-corps, cohérence de diamètre et comportement après répétition contrôlée.", practical: "Une salle peut combiner disques à poignées pour machines et musculation avec bumper plates pour plateformes. Un distributeur doit expliquer clairement l’usage afin d’éviter qu’un disque non prévu soit vendu comme produit de chute.", risks: "Le mot bumper ne garantit pas une performance identique. Un sol inadéquat, une chute hors usage, une barre incompatible ou une promesse de rebond non mesurée peuvent créer dommages et litiges.", comparison: [["Disque fonte/acier", "Compact et musculation", "Pas de chute présumée"], ["Disque revêtu", "Préhension et surface", "Vérifier noyau et liaison"], ["Bumper entraînement", "Travail de plateforme", "Épaisseur et rebond"], ["Bumper compétition", "Dimensions et présentation ciblées", "Critères plus exigeants à préciser"]], checklist: ["Exercices et chute autorisée", "Barres et alésage", "Diamètre et épaisseur", "Poids et tolérance", "Sol et plateforme", "Bruit et voisinage", "Rangement", "Inspection de l’insert", "Marquage", "Politique d’usage"], faq: [["Tous les bumper plates peuvent-ils être lâchés ?", "L’usage doit être confirmé pour le modèle, le poids, la hauteur et le sol."], ["Pourquoi l’épaisseur compte-t-elle ?", "Elle limite le nombre de disques chargeables sur la barre."], ["Peut-on mélanger les types ?", "Oui, si les zones et usages sont clairement définis."], ["Quel est le moins cher ?", "Le coût dépend matière, poids, volume, emballage et durée d’usage, pas seulement du type."]], links: [["weight-plates-category", "Voir les disques"], ["bumper-manufacturing-guide", "Comprendre la fabrication"], ["training-vs-competition-bumper-plates", "Entraînement ou compétition"], ["contact", "Comparer des modèles"]] },
  { id: "bumper-manufacturing-guide", enPath: "/resources/how-are-bumper-plates-made", frPath: "/fr/blog/fabrication-bumper-plates", title: "Comment sont fabriqués les bumper plates ? Processus & QC", description: "Noyau, caoutchouc ou CPU, insert, moulage, finition, poids, alésage, contrôle qualité, emballage et critères fournisseur.", h1: "Comment sont fabriqués les bumper plates", keyword: "fabrication bumper plates", intent: "Compréhension du procédé et évaluation fournisseur",
    direct: "Un bumper plate est fabriqué en préparant la matière et l’insert, puis en formant ou moulant le corps, en contrôlant la liaison, en finissant le produit, en marquant le poids et en vérifiant masse, dimensions, alésage et aspect avant emballage.", definition: "Le bumper plate est un disque de diamètre conçu pour le travail avec barre olympique et une construction élastomère. Sa performance dépend de la matière, du moule, de l’insert, du procédé et du contrôle, pas du nom seul.", decision: "Demandez quelle matière réelle est utilisée, comment l’insert est maintenu, quels paramètres sont surveillés et comment la masse est corrigée. Comparez un échantillon aux données et à l’usage prévu.", process: "Les étapes typiques sont préparation et dosage matière, préparation de l’insert, chargement du moule, pression et température, démoulage, finition, marquage, conditionnement et stabilisation. L’ordre exact varie entre caoutchouc lié, caoutchouc vierge, CPU ou autre élastomère.", quality: "Mesurez masse, diamètre, épaisseur, alésage, planéité et insertion. Vérifiez surface, couleur, marquage, liaison et comportement lors d’un protocole contrôlé. Les critères de rebond ou de chute doivent être liés à une méthode, pas à un adjectif.", practical: "Dans l’usine, la cohérence dépend autant de la préparation matière et du moule que du contrôle final. Une variation de formulation, température ou temps peut changer surface et comportement ; elle doit donc être maîtrisée entre lots.", risks: "Un insert mal lié, une masse hors tolérance, un alésage incorrect, une porosité importante ou une variation entre poids peuvent apparaître même si la photo est correcte. Les poids légers demandent une attention spécifique à l’épaisseur et à l’usage.", comparison: [["Caoutchouc recyclé lié", "Gestion matière et densité", "Aspect et propriétés à valider"], ["Caoutchouc vierge", "Formulation maîtrisée", "Coût et odeur à comparer"], ["CPU", "Moulage et finition spécifiques", "Dureté et liaison à confirmer"], ["Insert", "Interface avec la barre", "Alésage, alignement et maintien"]], checklist: ["Déclaration matière", "Construction de l’insert", "Paramètres de moulage", "Poids et tolérance", "Diamètre et épaisseur", "Alésage", "Planéité", "Test d’usage", "Marquage", "Protection d’emballage"], faq: [["Tous les bumper plates sont-ils en caoutchouc ?", "Plusieurs élastomères et formulations existent ; demandez la matière réelle."], ["Comment contrôle-t-on le poids ?", "Par pesée selon une tolérance définie et correction ou tri selon le procédé."], ["Pourquoi l’insert est-il critique ?", "Il relie le disque à la barre et supporte des contraintes répétées."], ["Peut-on juger le rebond sur une vidéo ?", "Une vidéo aide, mais le protocole, le sol, la hauteur et le poids doivent être précisés."]], links: [["weight-plates-category", "Voir les bumper plates"], ["plates-guide", "Comparer les disques"], ["pre-shipment-inspection-free-weights", "Préparer une inspection"], ["contact", "Interroger la fabrication"]] },
  { id: "dumbbell-weighing-guide", enPath: "/resources/how-are-dumbbells-weighed", frPath: "/fr/blog/controle-poids-halteres-tolerance", title: "Comment contrôler le poids des haltères et la tolérance ?", description: "Méthode de pesée, échantillonnage, tolérance, étalonnage, paires, gamme et inspection pour achats professionnels d’haltères.", h1: "Comment les haltères sont-ils pesés et contrôlés ?", keyword: "tolérance poids haltères", intent: "Contrôle qualité avant expédition",
    direct: "Les haltères sont pesés avec un équipement adapté et une méthode définie. L’acheteur fixe la masse cible, la tolérance, l’unité, l’échantillonnage et le traitement des écarts avant production, puis contrôle plusieurs paires et plusieurs poids.", definition: "La tolérance de masse est l’écart acceptable entre la valeur marquée et la mesure obtenue selon une méthode convenue. Elle ne doit pas être remplacée par une affirmation vague de précision.", decision: "Déterminez d’abord l’usage et l’exigence commerciale, puis convenez de la tolérance réalisable avec le procédé. Précisez si le contrôle porte sur chaque pièce, chaque paire, un échantillon ou une combinaison.", process: "Vérifiez l’identification de la balance, sa plage, sa résolution, sa vérification et la tare. Posez l’haltère de façon stable, enregistrez valeur, code et lot, puis comparez au seuil. Les écarts entraînent tri, correction ou rejet selon le plan.", quality: "Échantillonnez des poids légers, moyens et lourds, différentes zones de palette et plusieurs moments de production. Comparez aussi les deux éléments d’une paire et la cohérence du marquage.", practical: "Une balance trop petite ou trop peu précise peut donner une fausse impression de contrôle. Pour une gamme, utilisez une feuille qui calcule écart absolu et relatif sans confondre kg et lb.", risks: "Tolérance non écrite, balance sans vérification, mesure sur une seule pièce, arrondi excessif, tare incorrecte et absence de trace par lot empêchent une décision fiable.", comparison: [["Contrôle 100 %", "Forte couverture", "Temps et coût supérieurs"], ["Échantillonnage", "Efficace si bien conçu", "Risque résiduel"], ["Écart absolu", "Simple en kg ou g", "Impact différent selon le poids"], ["Écart relatif", "Comparable entre poids", "Doit être défini clairement"]], checklist: ["Masse nominale", "Tolérance écrite", "Unité", "Balance et plage", "Résolution", "Vérification de l’instrument", "Plan d’échantillonnage", "Identification du lot", "Action en cas d’écart", "Archivage des mesures"], faq: [["Existe-t-il une tolérance universelle ?", "Non. Elle dépend du produit, du procédé, de l’usage et de l’accord commercial."], ["Faut-il peser chaque haltère ?", "Cela dépend du risque ; un plan d’échantillonnage peut être approprié."], ["Pourquoi tester plusieurs poids ?", "Les extrêmes peuvent présenter des risques de remplissage, liaison ou mesure différents."], ["Une balance domestique suffit-elle ?", "Elle peut manquer de plage, de résolution et de vérification pour une réception B2B."]], links: [["dumbbells-category", "Voir les haltères"], ["dumbbells-guide", "Choisir une gamme"], ["pre-shipment-inspection-free-weights", "Inspection avant expédition"], ["contact", "Définir un contrôle"]] },
  { id: "plate-materials-b2b", enPath: "/resources/cast-iron-rubber-urethane-weight-plates", frPath: "/fr/blog/disques-fonte-caoutchouc-polyurethane-comparaison", title: "Disques fonte, caoutchouc ou polyuréthane : comparaison B2B", description: "Comparez matière, construction, dimensions, finition, entretien, emballage, usage et coût total des disques professionnels.", h1: "Disques en fonte, caoutchouc ou polyuréthane : que choisir ?", keyword: "disques fonte caoutchouc polyuréthane comparaison", intent: "Comparaison matière avant achat",
    direct: "La fonte privilégie une construction simple et compacte ; le caoutchouc ajoute une surface élastomère courante ; le polyuréthane vise d’autres finitions et formulations. Le meilleur choix dépend de l’usage, de l’échantillon, du budget, du nettoyage, du stockage et du positionnement de gamme.", definition: "La matière annoncée peut désigner le corps, le revêtement ou les deux. Un disque revêtu conserve souvent un noyau et un insert dont la conception influence autant la qualité que la surface visible.", decision: "Comparez construction complète, alésage, épaisseur, masse, odeur, couleur, adhérence du revêtement, arêtes, marquage et comportement sur rack. Demandez comment la matière est contrôlée entre lots.", process: "La fonte est coulée puis usinée ou finie ; un disque revêtu ajoute préparation du noyau, moulage ou application de l’élastomère, liaison et finition. Le polyuréthane et les autres systèmes ont leurs propres paramètres de mélange et de moulage.", quality: "Contrôlez porosité, arêtes, planéité et finition pour la fonte ; surface, bulles, liaison, couleur et odeur pour les revêtements ; alésage, masse, insert et marquage pour tous.", practical: "Une gamme peut combiner fonte économique, disques à poignées pour machines et versions à finition supérieure pour zones visibles. Le nombre de familles doit rester compatible avec stock et réassort.", risks: "Choisir uniquement par le nom matière masque formulation, noyau, épaisseur et procédé. Une promesse de durabilité sans usage ni test comparable n’est pas vérifiable.", comparison: [["Fonte", "Compacte et lisible", "Finition et corrosion"], ["Caoutchouc", "Surface courante en salle", "Odeur et formulation"], ["PU", "Aspect et couleurs possibles", "Formulation et coût"], ["TPU/CPU", "Autres systèmes élastomères", "Échantillon et procédé à vérifier"]], checklist: ["Usage", "Corps et revêtement", "Alésage", "Diamètre et épaisseur", "Masse et tolérance", "Odeur", "Couleur", "Adhérence", "Nettoyage", "Coût rendu"], faq: [["Le PU est-il toujours meilleur ?", "Non. Il faut comparer formulation, construction, usage et échantillon."], ["La fonte rouille-t-elle ?", "Une surface endommagée ou exposée peut se corroder ; finition et entretien comptent."], ["Le caoutchouc a-t-il toujours une odeur ?", "L’intensité varie avec formulation, fabrication, stockage et ventilation."], ["Quel matériau est le moins cher ?", "Le coût dépend aussi du poids, de l’usinage, du revêtement, de l’emballage et du transport."]], links: [["weight-plates-category", "Voir les disques"], ["plates-guide", "Disques ou bumper plates"], ["landed-cost-free-weights", "Calculer le coût rendu"], ["contact", "Comparer des échantillons"]] },
  { id: "commercial-free-weight-rfq", enPath: "/resources/commercial-free-weight-rfq-checklist", frPath: "/fr/blog/rfq-equipements-poids-libres-checklist", title: "RFQ équipements de poids libres : checklist d’achat B2B", description: "Préparez une demande de prix comparable pour haltères, disques, racks, OEM, contrôle, emballage, Incoterm et livraison.", h1: "Checklist RFQ pour équipements de poids libres professionnels", keyword: "RFQ équipements de musculation checklist", intent: "Préparation d’une demande de devis",
    direct: "Une RFQ fiable décrit acheteur, marché, références, variantes, quantités, matières, tolérances, logo, emballage, inspection, destination et Incoterm. Sans cette base, les fournisseurs calculent des produits différents.", definition: "La Request for Quotation est un dossier qui permet de comparer prix et conditions pour une même spécification. Elle sépare exigences obligatoires, options et questions ouvertes.", decision: "Commencez par les données qui changent fortement le coût : construction, plage, volumes, outillage, personnalisation et conditionnement. Demandez au fournisseur de lister ses hypothèses et exclusions.", process: "Créez une nomenclature, ajoutez plans ou photos de référence, définissez contrôle et emballage, envoyez une version datée, organisez les questions, puis publiez une version finale avant comparaison.", quality: "Incluez valeurs cibles, tolérances, méthode de mesure, échantillonnage et critères visuels. Une phrase comme « qualité commerciale » n’indique ni ce qui sera mesuré ni ce qui sera refusé.", practical: "Utilisez un tableau par SKU avec une ligne par variante. Ajoutez une feuille logistique et une feuille OEM. Comparez prix, MOQ, échantillon, délai, validité, paiement et Incoterm séparément.", risks: "Images sans mesures, quantités globales sans détail, Incoterms mélangés, logo non fourni, exigence de conformité vague et changements non versionnés produisent des écarts de prix trompeurs.", comparison: [["Demande informelle", "Rapide", "Hypothèses cachées"], ["RFQ structurée", "Prix comparables", "Préparation nécessaire"], ["Option", "Éclaire un choix", "Ne pas confondre avec base"], ["Exigence", "Critère obligatoire", "Doit être vérifiable"]], checklist: ["Profil de l’entreprise", "Marché et canal", "SKU et quantités", "Matières", "Dimensions et tolérances", "Logo et emballage", "Échantillon", "Inspection", "Incoterm et destination", "Calendrier et paiement"], faq: [["Faut-il connaître tous les détails ?", "Non. Identifiez les questions ouvertes et demandez des options clairement séparées."], ["Peut-on envoyer une photo ?", "Oui comme référence, mais ajoutez mesures et caractéristiques importantes."], ["Combien de fournisseurs comparer ?", "Assez pour comprendre le marché sans perdre le contrôle des échanges et versions."], ["Pourquoi demander les exclusions ?", "Elles révèlent ce que le prix ne couvre pas."]], links: [["products-hub", "Préparer la liste produits"], ["factory-guide", "Évaluer le fournisseur"], ["landed-cost-free-weights", "Comparer le coût total"], ["contact", "Envoyer votre RFQ"]] },
  { id: "custom-logo-free-weights", enPath: "/resources/custom-logo-options-dumbbells-weight-plates", frPath: "/fr/blog/logo-halteres-disques-marque-privee", title: "Logo sur haltères et disques : options de marque privée", description: "Comparez moulage, impression, gravure, couleur, étiquette et emballage pour créer une gamme d’équipements fitness en marque privée.", h1: "Comment personnaliser haltères et disques avec votre logo", keyword: "haltères logo marque privée", intent: "Étude OEM et branding produit",
    direct: "Choisissez la technique de logo selon matière, surface, taille, couleur, volume et durée attendue. Fournissez un fichier vectoriel, une référence couleur, l’emplacement et une épreuve ; validez ensuite le produit et l’emballage sur un échantillon.", definition: "La marque privée consiste à commercialiser un produit sous l’identité de l’acheteur. Le logo est une composante visible, mais la référence, la qualité, l’étiquetage, le carton et le réassort font aussi partie du système de marque.", decision: "Un logo moulé ou en relief implique souvent un outillage différent d’une impression ou d’un badge. La gravure convient à certaines surfaces métalliques ; l’impression dépend de préparation, encre et protection. Choisissez après essai réel.", process: "Envoyez fichiers vectoriels et guide de marque, confirmez dimensions et position, recevez une épreuve, produisez un échantillon, vérifiez contraste et tenue, puis verrouillez version graphique et emballage.", quality: "Contrôlez orientation, taille, couleur, netteté, adhérence, répétabilité et correspondance entre produit, étiquette et carton. Une photo sous un éclairage non défini ne suffit pas pour approuver une teinte critique.", practical: "Pour réduire risque et MOQ au lancement, commencez parfois par un modèle existant avec adaptation visuelle. Une modification de forme peut être envisagée après validation du marché et des volumes.", risks: "Fichier basse définition, absence de dimensions, couleur nommée sans référence, texte non relu, droits de marque non vérifiés et approbation uniquement écran créent retards et rebut.", comparison: [["Impression", "Flexible pour graphisme", "Préparation et tenue"], ["Moulage", "Intégré au produit", "Outillage et MOQ"], ["Gravure", "Adaptée à certains métaux", "Contraste à vérifier"], ["Badge/insert", "Aspect distinctif", "Liaison et remplacement"]], checklist: ["Droits sur la marque", "Fichier vectoriel", "Référence couleur", "Dimensions", "Position", "Procédé", "Épreuve", "Échantillon", "Textes emballage", "Version de réassort"], faq: [["Quel format de logo envoyer ?", "Un fichier vectoriel propre, accompagné des références couleur et dimensions."], ["Peut-on personnaliser de petites quantités ?", "Le MOQ dépend du produit, du procédé et du nombre de variantes."], ["Le logo change-t-il le délai ?", "Oui s’il exige épreuve, outillage, matière ou emballage spécifique."], ["Qui valide les textes français ?", "Le propriétaire de la marque doit valider la version destinée à son marché."]], links: [["oem-private-label", "Processus OEM"], ["oem-sample-approval-free-weights", "Valider l’échantillon"], ["dumbbells-category", "Haltères personnalisables"], ["contact", "Envoyer un logo"]] },
  { id: "export-packaging-free-weights", enPath: "/resources/export-packaging-dumbbells-weight-plates", frPath: "/fr/blog/emballage-export-halteres-disques", title: "Emballage export des haltères et disques | Guide B2B", description: "Cartons, séparateurs, palettes, arrimage, marquage et contrôle pour réduire dommages et coûts lors du transport de poids libres.", h1: "Comment emballer haltères et disques pour l’export", keyword: "emballage export haltères disques", intent: "Prévention des dommages logistiques",
    direct: "Les poids libres nécessitent cartons dimensionnés pour la masse, renforts, séparations, protection des surfaces, palettes stables et arrimage. La fiche de colisage doit préciser unités, poids, dimensions, marquage et disposition.", definition: "L’emballage export est un système produit-carton-palette-conteneur conçu pour supporter manutentions, compression, vibrations, humidité et durée du trajet dans les limites prévues.", decision: "Partez du poids par unité et par carton, puis vérifiez ergonomie de manutention, résistance, vide interne et empilage. Un carton très épais ne corrige pas une charge mal répartie ou une palette instable.", process: "Validez d’abord le conditionnement unitaire, réalisez un carton, mesurez poids et dimensions, testez manutention, construisez le plan palette, protégez les angles, filmez et sanglez, puis documentez le chargement.", quality: "Contrôlez référence, quantité, séparation, fermeture, étiquette, poids, intégrité du carton et stabilité de palette. Photographiez avant et après fermeture pour conserver une preuve exploitable.", practical: "Pour un conteneur mixte, combinez masse des poids libres et volume des racks sans dépasser les contraintes. Planifiez l’ordre de chargement et de déchargement, et gardez les colis inspectables.", risks: "Cartons trop lourds, surfaces en contact, palettes surchargées, étiquettes incohérentes, humidité, vide non calé et absence de plan de déchargement augmentent sinistres et temps de réception.", comparison: [["Carton individuel", "Protection et identification", "Coût et volume"], ["Paire par carton", "Gestion de set", "Poids de manutention"], ["Palette", "Stabilité et déplacement", "Répartition de charge"], ["Caisse", "Protection ciblée", "Poids et coût supérieurs"]], checklist: ["Poids par unité", "Unités par carton", "Poids net et brut", "Protection des surfaces", "Résistance et fermeture", "Étiquette SKU", "Plan palette", "Film et sangles", "Photos de chargement", "Plan de réception"], faq: [["Quel poids maximum par carton ?", "Il dépend de la construction, des règles de manutention et du transport ; il doit être validé pour le projet."], ["Faut-il palettiser ?", "Souvent pour les poids lourds, mais la solution dépend du flux et du conteneur."], ["Comment éviter les frottements ?", "Utilisez séparations, housses ou protections adaptées et limitez le mouvement interne."], ["Pourquoi mesurer le carton final ?", "Ces données déterminent fret, chargement et réception."]], links: [["landed-cost-free-weights", "Calculer le coût rendu"], ["pre-shipment-inspection-free-weights", "Inspecter l’emballage"], ["factory", "Voir la préparation export"], ["contact", "Étudier un colisage"]] },
  { id: "free-weight-reorder-batch-consistency", enPath: "/resources/free-weight-reorder-batch-consistency", frPath: "/fr/blog/reassort-halteres-disques-coherence-lots", title: "Réassort haltères et disques : cohérence entre lots", description: "Maîtrisez référence, matière, couleur, poids, logo, emballage et contrôle pour obtenir des réassorts cohérents entre productions.", h1: "Comment maintenir la cohérence des haltères et disques entre lots", keyword: "réassort haltères cohérence lots", intent: "Sécurisation des commandes répétées",
    direct: "Un réassort cohérent reprend code modèle, spécification, échantillon, matière, couleur, logo, emballage et critères du lot approuvé. Toute modification de fournisseur, outil, formulation ou procédé doit être évaluée avant production.", definition: "La cohérence de lot est la maîtrise des écarts acceptables entre productions successives. Elle ne signifie pas identité parfaite, mais stabilité dans les limites définies pour la fonction et la présentation.", decision: "Classez les caractéristiques en critiques, visuelles majeures et mineures. Conservez une référence physique ou des données mesurées, puis précisez quelles modifications exigent un nouvel échantillon.", process: "Émettez le bon de commande avec version, comparez matières et composants, produisez un échantillon de préproduction si nécessaire, contrôlez début de série, mesurez la production et rapprochez emballage et marquage du lot précédent.", quality: "Comparez masse, dimensions, teinte, brillance, texture, logo, poignée, insert et carton. Utilisez des conditions d’observation cohérentes pour la couleur et gardez les relevés associés au lot.", practical: "Les produits exposés ensemble dans une salle révèlent rapidement les écarts de forme ou couleur. Pour un distributeur, une référence modifiée sans notification peut aussi perturber photos, fiches et retours clients.", risks: "Commander uniquement par ancien nom, perdre l’échantillon, accepter une matière équivalente sans preuve, changer de couleur écran et ne pas contrôler le début de série sont les causes classiques de divergence.", comparison: [["Même code", "Continuité administrative", "Vérifier version réelle"], ["Échantillon physique", "Référence tangible", "Stockage et vieillissement"], ["Données mesurées", "Comparaison objective", "Méthode identique nécessaire"], ["Photo", "Trace utile", "Couleur et échelle limitées"]], checklist: ["Code et version", "Référence approuvée", "Matière et fournisseur", "Couleur", "Dimensions", "Masse", "Logo", "Emballage", "Notification de changement", "Contrôle début de série"], faq: [["Un réassort sera-t-il exactement identique ?", "Des variations existent ; les limites acceptables doivent être définies et contrôlées."], ["Faut-il refaire un échantillon ?", "Oui si un élément critique change ou si l’intervalle et le risque le justifient."], ["Comment contrôler la couleur ?", "Utilisez une référence et des conditions d’observation convenues, pas seulement un écran."], ["Pourquoi garder les données du lot ?", "Elles permettent d’expliquer et traiter les écarts futurs."]], links: [["oem-sample-approval-free-weights", "Créer une référence"], ["pre-shipment-inspection-free-weights", "Inspecter le réassort"], ["custom-logo-free-weights", "Stabiliser le branding"], ["contact", "Préparer un réassort"]] },
  { id: "commercial-dumbbell-set-planning", enPath: "/resources/plan-commercial-dumbbell-set", frPath: "/fr/blog/planifier-gamme-halteres-salle-sport", title: "Planifier une gamme d’haltères pour salle professionnelle", description: "Méthode pour définir poids, paliers, nombre de paires, rack, espace, fréquentation, budget, maintenance et réassort.", h1: "Comment planifier une gamme d’haltères pour une salle professionnelle", keyword: "gamme haltères salle de sport", intent: "Planification assortiment et espace",
    direct: "Planifiez la gamme à partir des utilisateurs, exercices, poids les plus demandés, paliers, nombre de paires et longueur de rack. Ajoutez circulation, nettoyage, remplacement et réassort avant de fixer le budget.", definition: "Une gamme d’haltères est une combinaison de poids et de quantités par poids, pas seulement un minimum et un maximum. Elle doit absorber la fréquentation et rester lisible sur le rack.", decision: "Une salle généraliste privilégie souvent une progression régulière ; un studio spécialisé peut concentrer plusieurs paires sur une plage. Les paliers et unités doivent correspondre aux habitudes du marché et à la clientèle.", process: "Estimez utilisateurs simultanés, recensez exercices, choisissez plage et pas, attribuez paires, calculez longueur et charge du rack, dessinez la circulation, puis confrontez au budget et au coût de remplacement.", quality: "Vérifiez que les têtes et poignées s’adaptent au rack pour chaque poids. Contrôlez aussi masse, marquage, stabilité, liaison et cohérence de finition sur les extrêmes de la série.", practical: "Il est souvent plus utile de doubler certains poids très sollicités que d’ajouter des variantes rarement utilisées. Les données d’usage d’un club existant améliorent la décision ; pour une ouverture, partez du concept et prévoyez une révision.", risks: "Sous-estimer les doublons, oublier le poids du rack chargé, bloquer la circulation, choisir un pas incohérent ou ne pas prévoir le remplacement produit une zone frustrante malgré une belle présentation.", comparison: [["Progression serrée", "Choix précis", "Plus de SKU et de rack"], ["Progression large", "Budget et espace réduits", "Sauts de charge"], ["Une paire", "Base simple", "Attente aux poids populaires"], ["Paires multiples", "Meilleur débit", "Budget et rangement"]], checklist: ["Profil utilisateur", "Exercices", "Poids min/max", "Paliers", "Paires par poids", "Dimensions réelles", "Longueur et charge du rack", "Circulation", "Budget", "Réassort"], faq: [["Quelle plage de poids choisir ?", "Elle dépend du public, des exercices et du concept de la salle."], ["Faut-il plusieurs paires ?", "Souvent pour les poids les plus utilisés aux heures de pointe."], ["Comment calculer le rack ?", "Utilisez les dimensions réelles de chaque variante et la capacité structurale."], ["Peut-on compléter plus tard ?", "Oui si le modèle, la finition et les références restent réassortissables."]], links: [["dumbbells-category", "Voir les haltères"], ["dumbbells-guide", "Comparer les constructions"], ["projects", "Planifier la zone"], ["contact", "Envoyer votre plage"]] },
  { id: "landed-cost-free-weights", enPath: "/resources/landed-cost-wholesale-free-weights", frPath: "/fr/blog/cout-rendu-import-halteres-disques", title: "Coût rendu des haltères et disques importés : méthode B2B", description: "Calculez produit, emballage, inspection, fret, assurance, droits, TVA, frais portuaires, livraison et déchargement.", h1: "Comment calculer le coût rendu des poids libres importés", keyword: "coût importation équipements musculation Chine", intent: "Calcul économique d’une importation",
    direct: "Le coût rendu additionne produit, personnalisation, emballage, échantillon, inspection, transport origine, fret, assurance, formalités, droits, taxes non récupérables, frais de destination, livraison et déchargement. Comparez toujours le même Incoterm et la même spécification.", definition: "Le coût rendu est le coût d’une marchandise disponible au point convenu, calculé selon les responsabilités du contrat. Il est distinct du seul prix usine et doit expliciter ce qui est inclus ou exclu.", decision: "Choisissez une unité pertinente : pièce, paire, kilogramme, palette ou SKU. Modélisez scénario de base et marge de risque, puis vérifiez tarifs et obligations avec transitaires, douanes et conseillers compétents.", process: "Fixez nomenclature et Incoterm, obtenez colisage, demandez fret, classez les produits, estimez droits et taxes, ajoutez destination, répartissez coûts communs, puis testez variations de volume, change et stockage.", quality: "Un produit moins cher peut coûter plus s’il exige davantage de rebut, de remplacement ou de manutention. Intégrez échantillon, inspection et réserve de qualité au lieu de les traiter comme dépenses invisibles.", practical: "Les poids libres saturent souvent la masse avant le volume ; les racks font l’inverse. Un conteneur mixte peut améliorer l’offre, mais demande une planification de chargement et une répartition de coûts cohérente.", risks: "Comparer EXW et DDP, oublier la TVA ou supposer sa récupération, utiliser des dimensions approximatives, ignorer stockage et déchargement, ou figer trop tôt le taux de fret fausse la marge.", comparison: [["EXW", "Départ usine", "Acheteur gère origine et suite"], ["FOB", "Jusqu’au chargement convenu", "Acheteur gère fret principal"], ["CIF/CFR", "Fret principal inclus selon terme", "Destination reste à chiffrer"], ["Rendu", "Plus proche du coût d’usage", "Vérifier exclusions et rôle importateur"]], checklist: ["Spécification identique", "Incoterm", "Colisage final", "Transport origine", "Fret et assurance", "Classement tarifaire", "Droits et TVA", "Frais destination", "Livraison/déchargement", "Réserve de risque"], faq: [["La TVA est-elle un coût ?", "Cela dépend de la situation de l’importateur et de sa récupération ; demandez un conseil adapté."], ["Quel Incoterm est le moins cher ?", "Aucun en soi : comparez coûts et responsabilités sur le même trajet."], ["Pourquoi le poids du carton compte-t-il ?", "Il influence manutention, palette, fret et réception."], ["Peut-on annoncer un droit de douane générique ?", "Non. Le classement, l’origine, la destination et la date doivent être vérifiés."]], links: [["export-packaging-free-weights", "Préparer l’emballage"], ["commercial-free-weight-rfq", "Comparer les devis"], ["products-hub", "Construire la nomenclature"], ["contact", "Obtenir le colisage"]] },
  { id: "oem-sample-approval-free-weights", enPath: "/resources/oem-free-weight-sample-approval-process", frPath: "/fr/blog/validation-echantillon-oem-halteres-disques", title: "Validation d’un échantillon OEM d’haltères et disques", description: "Processus d’approbation matière, dimensions, poids, couleur, logo, emballage et critères avant production de marque privée.", h1: "Comment valider un échantillon OEM de poids libres", keyword: "validation échantillon OEM équipements fitness", intent: "Approbation avant série",
    direct: "Validez l’échantillon contre une fiche datée : identité, matière, dimensions, masse, fonction, finition, couleur, logo, étiquette et emballage. Consignez chaque écart et n’autorisez la série qu’avec une version approuvée.", definition: "L’échantillon approuvé est une référence physique et documentaire pour la série. Il ne transforme pas automatiquement toutes les variantes en produits validés et ne remplace pas le contrôle de production.", decision: "Sélectionnez les variantes qui représentent les risques de matière, taille et poids. Une gamme d’haltères demande souvent des contrôles léger, moyen et lourd ; un rack peut demander montage et fonctionnement complet.", process: "Émettez la fiche, recevez l’échantillon identifié, photographiez l’emballage, mesurez, testez, classez les observations, demandez corrections, approuvez la version finale et reliez-la au bon de commande.", quality: "Utilisez instruments adaptés, références couleur, fichiers graphiques et critères d’aspect. Les résultats doivent inclure valeur, méthode et décision, pas seulement une coche de conformité.", practical: "Conservez un exemplaire chez l’acheteur et si possible une référence scellée à l’usine. En cas de changement, déterminez si une revue documentaire, une pièce partielle ou un nouvel échantillon complet est requis.", risks: "Approuver par messagerie sans version, tester une seule variante, oublier l’emballage, laisser un écart ouvert ou lancer la série avant réception crée des conflits difficiles à résoudre.", comparison: [["Photo", "Rapide et traçable", "Toucher, masse et couleur limités"], ["Échantillon physique", "Évaluation complète", "Temps et transport"], ["Golden sample", "Référence de série", "Doit être identifié et conservé"], ["Préproduction", "Vérifie changements", "À planifier avant volume"]], checklist: ["ID et version", "Matière", "Dimensions", "Poids/charge", "Fonction", "Finition", "Couleur", "Logo", "Étiquette", "Emballage"], faq: [["Un seul échantillon suffit-il ?", "Cela dépend du nombre de variantes et des risques ; les extrêmes peuvent nécessiter des pièces distinctes."], ["Peut-on approuver sur photo ?", "Pour certains points graphiques, oui ; pas toujours pour masse, toucher, couleur ou fonction."], ["Qui signe l’approbation ?", "Une personne autorisée côté acheteur, avec version et date."], ["Que faire après une modification ?", "Évaluer son impact et décider du niveau de revalidation."]], links: [["oem-private-label", "Processus OEM"], ["custom-logo-free-weights", "Valider le logo"], ["pre-shipment-inspection-free-weights", "Comparer la série"], ["contact", "Organiser un échantillon"]] },
  { id: "pre-shipment-inspection-free-weights", enPath: "/resources/pre-shipment-inspection-dumbbells-weight-plates", frPath: "/fr/blog/inspection-avant-expedition-halteres-disques", title: "Inspection avant expédition des haltères et disques", description: "Préparez échantillonnage, mesures, défauts, emballage, quantité, rapport et décision avant solde et expédition.", h1: "Comment inspecter haltères et disques avant expédition", keyword: "inspection avant expédition haltères", intent: "Contrôle final avant transport",
    direct: "Une inspection avant expédition vérifie quantité produite, échantillonnage, identité, masse, dimensions, fonction, aspect, logo et emballage par rapport aux documents approuvés. Le rapport doit permettre accepter, corriger, réinspecter ou refuser.", definition: "La PSI est un contrôle d’un lot suffisamment achevé et emballé, effectué avant départ. Elle réduit le risque mais ne garantit pas chaque unité si l’échantillonnage n’est pas exhaustif.", decision: "Définissez le plan avant production : moment, taille d’échantillon, défauts critiques/majeurs/mineurs, tests et action. L’inspecteur doit disposer de la dernière version et de l’échantillon ou de photos de référence.", process: "Vérifiez disponibilité du lot, tirez les cartons, contrôlez quantité et marquage, ouvrez plusieurs zones, mesurez les produits, testez les fonctions, inspectez l’emballage, photographiez les écarts et émettez un rapport signé.", quality: "Pour les haltères : poids, poignée, tête, liaison et surface. Pour les disques : masse, alésage, planéité, insert et marquage. Pour tous : SKU, nombre, carton, palette et cohérence avec la liste.", practical: "Ne laissez pas l’usine choisir uniquement les pièces faciles. L’échantillonnage couvre différentes palettes, cartons, variantes et moments de production. Les unités mesurées restent identifiables dans le rapport.", risks: "Inspection trop tôt, documents obsolètes, lot non terminé, échantillon biaisé, défauts sans classification et décision prise sans revoir les corrections réduisent fortement la valeur de la PSI.", comparison: [["Inspection interne", "Rapide et intégrée", "Indépendance limitée"], ["Tierce partie", "Regard indépendant", "Brief précis nécessaire"], ["100 %", "Couverture élevée", "Temps et coût"], ["Échantillonnage", "Efficace", "Risque résiduel"]], checklist: ["Version du bon de commande", "Lot terminé", "Plan d’échantillonnage", "Critères de défaut", "Instruments", "Tests produit", "Quantités", "Emballage", "Photos", "Décision et corrections"], faq: [["Quand inspecter ?", "Lorsque la production est suffisamment achevée et qu’une part représentative est emballée."], ["Qui choisit les échantillons ?", "L’inspecteur selon le plan, pas uniquement l’usine."], ["Une PSI remplace-t-elle le contrôle usine ?", "Non. Elle complète les contrôles de matière, processus et fin de ligne."], ["Que faire en cas d’échec ?", "Analyser les écarts, corriger, vérifier l’étendue et réinspecter si nécessaire."]], links: [["dumbbell-weighing-guide", "Contrôler le poids"], ["export-packaging-free-weights", "Contrôler l’emballage"], ["factory-guide", "Évaluer le système QC"], ["contact", "Définir l’inspection"]] },
  { id: "training-vs-competition-bumper-plates", enPath: "/resources/training-vs-competition-bumper-plates", frPath: "/fr/blog/bumper-plates-entrainement-vs-competition", title: "Bumper plates d’entraînement ou de compétition : guide B2B", description: "Comparez construction, dimensions, tolérance, insert, épaisseur, rebond, couleur, usage, contrôle et budget pour salles et distributeurs.", h1: "Bumper plates d’entraînement ou de compétition : différences", keyword: "bumper plates entraînement compétition", intent: "Choix de gamme et positionnement",
    direct: "Les bumper plates d’entraînement privilégient généralement un usage régulier et un budget de salle ; les versions de compétition visent des spécifications et une présentation plus encadrées. Vérifiez données réelles et protocole plutôt que l’étiquette commerciale.", definition: "Ces catégories décrivent un positionnement et un ensemble attendu de caractéristiques, mais elles ne garantissent pas à elles seules diamètre, épaisseur, tolérance ou comportement. La fiche du modèle fait foi.", decision: "Décidez si les utilisateurs pratiquent haltérophilie technique, entraînement général, cours, compétition ou vente spécialisée. Comparez espace sur barre, plateforme, bruit, précision recherchée et prix rendu.", process: "Demandez données par poids, inspectez insert et surface, mesurez masse et dimensions, observez un protocole d’usage, puis comparez packaging et réassort. Les poids légers et lourds peuvent nécessiter des évaluations différentes.", quality: "Contrôlez diamètre, épaisseur, alésage, planéité, masse, marquage, couleur, liaison de l’insert et variation entre pièces. Si un chiffre de rebond est annoncé, demandez méthode et conditions.", practical: "Une salle peut réserver les versions plus précises à une zone technique et utiliser une gamme d’entraînement ailleurs. Un distributeur doit éviter que la dénomination compétition soit utilisée sans preuves cohérentes.", risks: "Payer une étiquette, ignorer l’épaisseur, utiliser sur un sol inadapté, supposer une tolérance ou mélanger des diamètres peut annuler le bénéfice attendu.", comparison: [["Entraînement", "Usage courant et budget", "Spécification variable"], ["Compétition", "Positionnement technique", "Données et preuves nécessaires"], ["Insert simple", "Construction courante", "Liaison à surveiller"], ["Insert renforcé", "Interface plus élaborée", "Coût et contrôle"]], checklist: ["Usage", "Diamètre", "Épaisseur", "Alésage", "Tolérance de masse", "Insert", "Rebond", "Couleur", "Plateforme", "Budget rendu"], faq: [["Compétition signifie-t-il certifié ?", "Non. Une certification ou homologation doit être explicitement prouvée pour le modèle."], ["Les disques d’entraînement sont-ils moins durables ?", "Pas nécessairement ; construction, usage et entretien déterminent la performance."], ["Pourquoi mesurer l’épaisseur ?", "Elle détermine la charge possible sur la barre."], ["Peut-on mélanger les gammes ?", "Oui si dimensions, usages et règles de la zone sont compatibles."]], links: [["weight-plates-category", "Voir les bumper plates"], ["bumper-manufacturing-guide", "Fabrication"], ["plates-guide", "Comparer les familles"], ["contact", "Choisir une gamme"]] }
];

const contextAngles = [
  "Pour les importateurs, la décision doit rester traçable : chaque hypothèse de prix, de qualité ou de délai est associée à un document. Pour les exploitants, le même raisonnement est traduit en usage, maintenance et réception. Commencez par distinguer les faits confirmés, les options proposées et les points encore inconnus. Un fait doit renvoyer à une fiche, une mesure, un échantillon ou une preuve liée au modèle ; une option doit préciser son effet sur MOQ, prix et délai ; une inconnue reste ouverte jusqu’à ce qu’une personne responsable la résolve. Cette discipline évite que le devis soit plus précis que le produit réellement défini. Préparez aussi la réception dès la commande. Désignez qui contrôlera les colis, quels instruments seront disponibles, où seront stockés les produits et comment un écart sera documenté. Pour une gamme lourde, la facilité d’accès aux échantillons, la capacité de manutention et l’identification des palettes influencent la qualité du contrôle. Le retour d’expérience de la première livraison doit ensuite modifier la spécification ou le plan de contrôle lorsque cela apporte une amélioration mesurable.",
  "Un distributeur doit pouvoir transformer les données usine en fiche produit, contrôle de réception et procédure de réassort. Une salle cherche surtout une configuration utilisable et maintenable ; le dossier doit servir les deux lectures. Pour le distributeur, notez les données qui doivent rester cohérentes entre catalogue, étiquette, carton et produit : nom, matière, poids, dimensions, avertissements, code et photographie. Pour l’exploitant, ajoutez emplacement, fréquence, nettoyage, inspection, stockage et remplacement. Lorsque les deux listes divergent, la version d’achat doit les réunir sans simplifier un point technique. Le réassort mérite une règle avant la première commande. Conservez code modèle, version, échantillon ou mesures, fichier du logo, teinte, unité d’emballage et critères d’acceptation. Demandez au fabricant de notifier les changements de matière, outil, sous-traitant ou procédé. Selon l’impact, choisissez une revue documentaire, un nouvel échantillon ou un contrôle renforcé. Cette mémoire réduit le risque de recevoir un produit seulement similaire à celui déjà présenté ou installé.",
  "Les marchés francophones n’ont pas tous les mêmes règles, taxes ni responsabilités. La spécification industrielle peut être commune, mais les informations, avertissements, acteurs économiques et formalités doivent être vérifiés pour la destination réelle. Identifiez le pays de mise sur le marché, le canal B2B ou B2C, le rôle de l’importateur et les caractéristiques qui pourraient placer le produit dans un régime particulier. Ne demandez pas un marquage ou un certificat générique : demandez l’analyse applicable au modèle et vérifiez titulaire, portée, date et documents associés. Pour l’Union européenne, la sécurité générale, la traçabilité, l’information produit et l’existence d’un opérateur économique responsable doivent être examinées. Le marquage CE n’est pas une marque de qualité universelle et ne s’applique que lorsqu’une législation le prévoit. Pour la Suisse ou le Canada, l’acheteur doit vérifier les exigences locales séparément. PowerBaseFit peut fournir données de construction, emballage et fabrication, mais l’importateur conserve les responsabilités attachées à son rôle et doit obtenir un avis compétent lorsque la classification ou la conformité reste incertaine.",
  "Une bonne décision sépare ce qui est confirmé, ce qui reste à tester et ce qui relève du professionnel local. Cette séparation évite de transformer une option commerciale en promesse technique ou réglementaire. Utilisez trois colonnes dans le suivi : confirmé par preuve, à valider sur échantillon ou série, et à vérifier pour la destination. Les dimensions, masses et matériaux peuvent être confirmés par le fabricant ; la couleur, le toucher ou le comportement peuvent demander un échantillon ; les obligations de mise sur le marché peuvent nécessiter l’importateur ou un spécialiste. Ajoutez ensuite une règle de changement. Une modification de texte d’étiquette n’a pas le même impact qu’un nouveau noyau, un autre câble ou une nouvelle formulation. Documentez motif, lots touchés, effet possible et niveau de revalidation. Cette démarche réduit les validations implicites et facilite une décision lorsque le calendrier est serré. Elle protège également le fournisseur contre une attente non écrite et l’acheteur contre une substitution non évaluée.",
  "Le coût d’un défaut ne se limite pas au remplacement : réception, tri, stockage, communication, rupture et transport peuvent dépasser la valeur de la pièce. Les critères de contrôle doivent donc suivre le risque économique. Classez les caractéristiques selon sécurité, fonction, compatibilité, présentation et logistique. Un écart d’alésage ou de montage peut bloquer l’usage ; une variation de teinte peut bloquer une gamme de marque ; un carton trop lourd peut ralentir chaque réception. Attribuez des contrôles plus forts aux conséquences les plus coûteuses. La prévention doit aussi rester proportionnée. Un contrôle à 100 % n’est pas automatiquement préférable si la méthode est instable ou si elle endommage l’emballage. Combinez maîtrise du procédé, échantillonnage, tests ciblés et inspection indépendante selon le risque. Mesurez le coût de l’échantillon et du contrôle face au coût probable d’une erreur, puis inscrivez la décision dans la RFQ afin que tous les fournisseurs chiffrent la même exigence.",
  "Les données de catalogue ouvrent la discussion, mais l’achat se conclut sur une version datée. Modèle, matière, dimensions, marquage, conditionnement et inspection doivent rester cohérents du devis au lot expédié. Créez une nomenclature avec une ligne par SKU, joignez les plans et fichiers graphiques, puis identifiez la version dans le bon de commande, l’échantillon et le rapport d’inspection. Lorsqu’une question reçoit une réponse, mettez à jour le document de référence au lieu de laisser l’information dans un message isolé. Avant le solde, rapprochez quantité, version, résultats de contrôle, emballage et liste de colisage. Après réception, consignez les écarts, les variantes réellement consommées et les difficultés de manutention. Ces données améliorent le prochain achat et permettent de supprimer les options sans valeur. Une chaîne documentaire simple mais tenue à jour est plus utile qu’un grand nombre de fichiers contradictoires ou qu’une promesse générale de qualité."
];

function guideImages(profile: FrenchGuideProfile): LocalizedImage[] {
  const sources = ["/assets/dumbbell-production.webp", "/assets/resource-cnc-machining.webp", "/assets/resource-plate-finishing.webp"];
  const slug = profile.frPath.split("/").pop()!;
  return sources.map((src, index) => ({ id: `image-${index + 1}`, src: frenchImagePath(src, slug, index), alt: index === 0 ? `Expérience de fabrication PowerBaseFit liée au guide ${profile.h1}` : index === 1 ? "Usinage réel de composants d’équipements de musculation" : "Contrôle réel de finition de disques et équipements", caption: index === 0 ? "Processus réel de fabrication PowerBaseFit." : index === 1 ? "Usinage réel dans l’environnement de production." : "Contrôle réel de surface et de finition." }));
}

export function frenchGuideVersion(profile: FrenchGuideProfile): LocalizedContentVersion {
  const index = frenchGuideProfiles.indexOf(profile);
  return { locale: "fr", translationStatus: "localized", reviewStatus: "approved", publishStatus: "published", slug: profile.frPath.split("/").pop()!, publicPath: profile.frPath, title: profile.title, description: profile.description, h1: profile.h1,
    body: [frAnswer("reponse-rapide", "Réponse rapide", profile.direct), frDefinition("definition", profile.h1, profile.definition), frText("contexte", "Pourquoi cette décision est importante en B2B", profile.decision, contextAngles[index % contextAngles.length]), frTable("comparaison", "Tableau comparatif", ["Option ou critère", "Intérêt", "Point à vérifier"], profile.comparison), frText("methode", "Méthode étape par étape", profile.process, "Transformez chaque étape en livrable : liste, fiche, échantillon, relevé, rapport ou approbation. Indiquez auteur, date et version. Lorsqu’une donnée change, identifiez les pages et décisions qui doivent être mises à jour au lieu de conserver plusieurs références contradictoires."), frText("controle", "Contrôle qualité et preuves", profile.quality, "Une preuve utile doit être reliée au produit, au lot et au critère. Une photographie illustre ; une mesure quantifie ; un échantillon matérialise ; une inspection vérifie un échantillon du lot. Aucun de ces éléments ne couvre seul tous les risques."), frText("terrain", "Conseils pratiques pour importateurs et distributeurs", profile.practical, "Demandez au fournisseur d’expliquer ce qu’il fera si un résultat dépasse la limite. Le processus de tri, correction, nouvelle mesure et approbation révèle souvent davantage la maturité opérationnelle qu’une promesse d’absence totale de défaut."), frText("risques", "Risques et erreurs fréquentes", profile.risks, "Ne transférez pas automatiquement au fabricant les responsabilités de l’importateur, du distributeur ou de l’exploitant. Pour l’Union européenne, la sécurité générale, la traçabilité et l’existence d’un opérateur économique responsable doivent être étudiées selon le produit et le canal. Le marquage CE ne s’applique que lorsqu’un texte le prévoit ; il ne faut ni le promettre ni le demander comme décoration."), frText("cahier-des-charges", `Construire le cahier des charges pour « ${profile.keyword} »`, "Le cahier des charges distingue caractéristiques obligatoires, valeurs cibles, tolérances, options et informations à proposer par le fabricant. Chaque caractéristique importante indique une méthode de contrôle et le moment où elle sera vérifiée. Les plans, photographies et échantillons sont identifiés par un code afin qu’ils ne remplacent pas silencieusement la version écrite.", "Pour une gamme, créez une ligne par SKU et ne cachez pas les différences derrière une seule description. Poids, dimensions, matière, couleur, logo, unité d’emballage et quantité sont saisis séparément. Cette structure permet aussi au fournisseur de signaler une limite ou une alternative sans modifier le reste du projet."), frText("qualification", "Qualifier la réponse du fournisseur", "Une réponse utile reprend les exigences et confirme ce qui est possible, optionnel ou non applicable. Elle identifie les procédés utilisés, les données encore manquantes, les responsables et les délais. Une simple mention « oui, possible » ne suffit pas lorsqu’une caractéristique dépend de matière, outil, sous-traitant ou volume.", "Comparez la qualité des questions posées par le fournisseur. Un interlocuteur qui demande usage, variantes, tolérance, marché, emballage et destination cherche à définir le projet. Demandez néanmoins des preuves et ne confondez pas une communication précise avec la validation finale du produit."), frText("conformite", "Sécurité, conformité et responsabilités sur le marché", "Les exigences dépendent du produit, de sa construction, de son usage, de sa destination et du rôle de chaque opérateur. Pour l’Union européenne, l’importateur doit vérifier les règles applicables, la sécurité générale, la traçabilité, les informations requises et l’opérateur économique responsable. Les notices et avertissements doivent être adaptés au marché lorsque la réglementation ou l’usage l’exige.", "Le marquage CE n’est obligatoire que pour les produits couverts par une législation qui le prévoit. Un haltère mécanique simple, une machine motorisée et un accessoire connecté ne doivent pas être traités comme une seule catégorie. Demandez l’analyse et les documents du modèle réel, puis faites-les vérifier par une personne compétente ; PowerBaseFit ne transforme pas une demande générale en déclaration automatique de conformité."), frText("logistique", "Préparer emballage, transport et réception", "La logistique est intégrée avant le devis final. Demandez poids net, poids brut, dimensions, unités par carton, nombre de cartons, plan palette et protection des surfaces. Vérifiez aussi comment l’inspection peut ouvrir puis refermer les colis sans dégrader la protection. Les poids libres et les structures volumineuses ont des contraintes différentes dans un chargement mixte.", "À destination, prévoyez rendez-vous, accès camion, moyens de déchargement, zone tampon, équipes et méthode de comptage. Les cartons sont rapprochés de la liste, les dommages sont photographiés avant déplacement et les produits de plusieurs palettes sont échantillonnés. Une réception préparée sépare plus facilement dommage de transport, erreur de quantité et écart de fabrication."), frText("cout", "Prix, MOQ, délai et coût total", "Le prix est comparé uniquement lorsque modèle, quantité, personnalisation, emballage, inspection et Incoterm sont identiques. Le MOQ peut venir de la matière, du moule, du marquage, du carton ou du nombre de variantes. Demandez le minimum par SKU et le minimum global séparément.", "Le calendrier comprend clarification, épreuve, échantillon, validation, approvisionnement, production, inspection, réservation et transport. Ajoutez une marge pour les corrections et la destination. Un délai court obtenu en supprimant l’échantillon ou le contrôle ne constitue pas nécessairement un gain."), frText("experience", "Informations de première main PowerBaseFit", "Dans la production de poids libres, les problèmes utiles à prévenir sont concrets : variation de masse, liaison, alésage, surface, marquage, friction pendant le transport et incohérence d’emballage. Pour les racks et accessoires, géométrie, soudure, revêtement, quincaillerie, câbles et montage deviennent prioritaires.", "PowerBaseFit organise ses échanges autour de modèles, versions, échantillons et critères. Les détails réellement applicables sont confirmés pour la commande ; aucune capacité, certification, durée de vie ou expérience client francophone n’est inventée pour remplir ce guide."), frText("reception", "Boucler l’achat après réception", "Le contrôle à destination compare produits, cartons et documents au lot expédié. Les écarts sont quantifiés par SKU et gravité, puis communiqués avec photos, mesures et références de colis. Conservez quelques unités et les données importantes pour la prochaine commande, surtout lorsque couleur, masse, interface ou finition doivent rester cohérentes.", "Organisez un retour d’expérience entre achats, logistique, vente et utilisateurs. Les remarques répétées deviennent des exigences mesurables ; les options inutiles peuvent être supprimées. Un réassort maîtrisé repose sur cette mémoire du projet et sur une version stable, pas sur la recherche d’un produit visuellement similaire plusieurs mois plus tard."), frChecklist("checklist", "Checklist opérationnelle", profile.checklist), frText("action", "Passer du guide à la demande d’achat", "Reprenez la checklist dans votre RFQ. Joignez les données disponibles, classez les exigences obligatoires et les options, puis demandez au fournisseur de répondre point par point. Les questions non résolues restent visibles jusqu’à l’approbation.", "Avant paiement du solde et expédition, rapprochez le rapport de contrôle, la liste de colisage et la version approuvée. Après réception, conservez les observations utiles pour le prochain réassort. Cette boucle améliore la décision sans dépendre d’affirmations marketing.")],
    faq: profile.faq.map(([question, answer], i) => ({ id: `faq-${i + 1}`, question, answer })), author: frenchEditorialAuthor, reviewedBy: frenchTechnicalReviewer,
    schemaData: { brand: "PowerBaseFit", manufacturer: "PowerBaseFit", category: "Guide d’achat B2B", specifications: [{ name: "Sujet", value: profile.keyword }, { name: "Intention", value: profile.intent }], breadcrumbs: [{ name: "Accueil", path: "/fr" }, { name: "Guides", path: "/fr/blog" }, { name: profile.h1, path: profile.frPath }], extra: { primaryKeyword: profile.keyword, searchIntent: profile.intent } },
    images: guideImages(profile), internalLinks: profile.links.map(([targetContentId, label]) => ({ targetContentId, label })), canonicalData: { mode: "self" }, hreflangData: { include: true }, updatedAt: "2026-07-20T08:00:00.000Z", publishedAt: "2026-07-20T08:00:00.000Z", version: 1 };
}
